@push('scripts')
    <script>
        (() => {
            const preloader = document.getElementById('site-preloader');
            const rect = document.getElementById('birge-loader-progress');

            if (!preloader || !rect) {
                return;
            }

            const logoWidth = 200;

            let progress = 0;
            let loadingFinished = false;

            function setProgress(value) {
                progress = Math.min(value, 100);
                rect.setAttribute('width', logoWidth * progress / 100);
            }

            const fakeLoading = setInterval(() => {
                if (!loadingFinished && progress < 90) {
                    setProgress(progress + Math.random() * 6 + 1);
                }
            }, 90);

            window.addEventListener('load', () => {
                loadingFinished = true;
                clearInterval(fakeLoading);

                const finishLoading = setInterval(() => {
                    if (progress >= 100) {
                        clearInterval(finishLoading);

                        setTimeout(() => {
                            preloader.classList.add('is-hidden');

                            preloader.addEventListener(
                                'transitionend',
                                (e) => {
                                    if (e.propertyName === 'transform') {
                                        preloader.remove();
                                    }
                                },
                                { once: true }
                            );
                        }, 250);

                        return;
                    }

                    setProgress(progress + 4);
                }, 16);
            });
        })();
    </script>

    <script>
        (() => {
            const preloader = document.getElementById('site-preloader')

            if (!preloader) {
                return
            }

            const isLivewireNavigation =
                sessionStorage.getItem('is-livewire-navigation') === '1'

            if (isLivewireNavigation) {
                preloader.remove()
                return
            }

            document.addEventListener('livewire:navigate', () => {
                sessionStorage.setItem('is-livewire-navigation', '1')
            })

            window.addEventListener('beforeunload', () => {
                sessionStorage.removeItem('is-livewire-navigation')
            })
        })()
    </script>

@endpush
